generated_oml:
// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor measuring input current I_M for the axis motor"
    DTDFVocab:producedData CurrentDataTransmitted
]

instance MotorMountedEncoder : DTDFVocab:SensingComponent [
    base:desc "Position encoder mounted on the motor shaft providing angle feedback"
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance GearboxSecondaryEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox delivering downstream angle information"
    DTDFVocab:producedData GearboxEncoderDataTransmitted
]

// C4: Physical-to-virtual interaction (Data transmitted)
instance CurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorMountedEncoder
]

instance GearboxEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxSecondaryEncoder
]

// C10: Data (traces stored in the digital shadow)
instance TorqueTraceData : DTDFVocab:Data [
    base:desc "Time‑stamped torque (τ) array derived from motor current and encoder data"
    DTDFVocab:fromData CurrentDataTransmitted, MotorEncoderDataTransmitted, GearboxEncoderDataTransmitted
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

instance AngularVelocityTraceData : DTDFVocab:Data [
    base:desc "Time‑stamped angular velocity (ω) array computed from the two encoders"
    DTDFVocab:fromData MotorEncoderDataTransmitted, GearboxEncoderDataTransmitted
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

// C10: Models
instance AxisSysMLBlockModel : DTDFVocab:Model [
    base:desc "SysML block diagram of the first axis (motor, gearwheel gearbox, cycloidal gearbox)"
    DTDFVocab:inputTo SysMLEnabler
]

instance CoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink implementation of a combined Coulomb‑viscous friction model for the axis"
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

instance StribeckFrictionModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink Stribeck friction model used for static‑kinetic transition identification"
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

instance DahlFrictionModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink Dahl friction model capturing stick‑slip dynamics"
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

instance LuGreFrictionModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink LuGre friction model providing a white‑box representation of friction"
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

instance DataCalculationModel : DTDFVocab:Model [
    base:desc "Data‑calculation model that derives torque, angular velocity and acceleration from raw sensor streams"
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

// C11: Enablers
instance AssetAdministrationShellEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell (AAS) serving as the digital twin container and data repository"
    DTDFVocab:enables DynamicModelExchangeService
]

instance SysMLEnabler : DTDFVocab:Enabler [
    base:desc "SysML tooling used for engineering model management"
    DTDFVocab:enables RealTimeFrictionIdentificationService
]

instance MATLABSimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink runtime executing friction models and data‑calculation algorithms"
    DTDFVocab:enables FrictionParameterExtractionService, DataVisualizationService, RealTimeFrictionIdentificationService
]

instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker providing live streaming of sensor data (current I_M, angle) to the digital twin"
    DTDFVocab:enables RealTimeFrictionIdentificationService
]

instance WebDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard visualizing measured vs. simulated data for operators"
    DTDFVocab:enables DataVisualizationService
]

// C6: Services
instance RealTimeFrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time identification of static, kinetic and viscous friction parameters during operation"
    DTDFVocab:provides FrictionParametersInsight, ControlParameterUpdateAction
]

instance FrictionParameterExtractionService : DTDFVocab:Service [
    base:desc "Extraction of friction model parameters from the processed torque and velocity traces"
    DTDFVocab:provides FrictionParametersInsight
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Visualization of measured versus simulated torque and angular‑velocity data on an operator dashboard"
    DTDFVocab:provides MeasuredVsSimulatedVisualizationInsight
]

instance DynamicModelExchangeService : DTDFVocab:Service [
    base:desc "Dynamic exchange of white‑box (e.g., LuGre) and black‑box friction models during robot operation"
    DTDFVocab:provides ModelExchangeInsight
]

// C17: Insights / Actions
instance FrictionParametersInsight : DTDFVocab:Insight [
    base:desc "Identified static, kinetic and viscous friction parameters for the axis"
]

instance ControlParameterUpdateAction : DTDFVocab:Action [
    base:desc "Automatic update of robot controller parameters with the extracted friction values"
    DTDFVocab:IsAutomatic true
]

instance MeasuredVsSimulatedVisualizationInsight : DTDFVocab:Insight [
    base:desc "Comparison view highlighting deviations between measured data and simulation outputs"
]

instance ModelExchangeInsight : DTDFVocab:Insight [
    base:desc "Status of the active friction model (white‑box or black‑box) and its impact on motion accuracy"
]

// C2: Acting Component (digital shadow)
instance FrictionShadow : DTDFVocab:ActingComponent [
    base:desc "Single digital shadow aggregating measured data traces, simulation modules (SimulationM, SimulationGW, SimulationGB) and providing friction services"
    base:contains TorqueTraceData, AngularVelocityTraceData, AxisSysMLBlockModel, CoulombViscousFrictionModel, StribeckFrictionModel, DahlFrictionModel, LuGreFrictionModel, DataCalculationModel
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous, real‑time processing of live data streams to generate and update friction parameters during robot operation."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "One concrete digital shadow (FrictionShadow) instantiated for asset MABI, linked to processing components (SimulationM, SimulationGW, SimulationGB) that consume measured data traces and produce simulated traces, all governed by the Digital Shadow Reference Model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operated (run‑time) stage for online friction monitoring and control‑loop improvement."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Full traceability of each data point to its source and processing model; validation by comparing simulated friction‑free and friction‑inclusive models against measured torque/velocity data; multi‑physics aware identification ensures model accuracy over time."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data transmitted from the robot to the digital shadow via MQTT protocol."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of the Asset Administration Shell (AAS) standard and SysML for model representation."
]
